/* ---------- Contato ---------- */
function Contato() {
  const [form, setForm] = useState({ nome: "", telefone: "", mensagem: "" });

  const handleSubmit = (e) => {
    e.preventDefault();
    const text = `Olá! Meu nome é ${form.nome || "—"}.\nTelefone: ${
      form.telefone || "—"
    }\nMensagem: ${form.mensagem || "—"}`;
    window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(text)}`, "_blank");
  };

  const inputStyle = {
    background: "rgba(244,235,214,0.05)",
    border: `1px solid ${COLORS.line}`,
    color: COLORS.paper,
    fontFamily: "'Work Sans', sans-serif",
  };

  return (
    <section id="contato" className="py-24 px-6" style={{ background: COLORS.ink }}>
      <div className="max-w-6xl mx-auto grid md:grid-cols-2 gap-12">
        <Reveal>
          <Faixa number="07" lado="B" title="Contato" />
          <h2
            style={{
              fontFamily: "'Zilla Slab', serif",
              fontWeight: 700,
              color: COLORS.paper,
              fontSize: "clamp(1.9rem, 3.4vw, 2.6rem)",
            }}
          >
            Fala com a gente
          </h2>
          <p
            className="mt-3 max-w-sm"
            style={{ color: "rgba(244,235,214,0.7)", fontFamily: "'Work Sans', sans-serif" }}
          >
            Dúvida sobre um título, quer reservar uma mesa pra noite de show
            ou só quer saber se aquele disco chegou — manda mensagem.
          </p>

          <div className="mt-8 flex flex-col gap-4">
            <a
              href={`https://wa.me/${WHATSAPP_NUMBER}`}
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-3"
              style={{ color: COLORS.paper, fontFamily: "'Work Sans', sans-serif" }}
            >
              <span
                className="w-10 h-10 rounded-full flex items-center justify-center"
                style={{ background: "rgba(232,162,58,0.15)" }}
              >
                <MessageCircle size={18} color={COLORS.paper} />
              </span>
              (85) 99636-9906
            </a>
            <a
              href="tel:+5585996369906"
              className="flex items-center gap-3"
              style={{ color: COLORS.paper, fontFamily: "'Work Sans', sans-serif" }}
            >
              <span
                className="w-10 h-10 rounded-full flex items-center justify-center"
                style={{ background: "rgba(232,162,58,0.15)" }}
              >
                <Phone size={18} color={COLORS.paper} />
              </span>
              Ligar para a loja
            </a>
            <a
              href={INSTAGRAM_URL}
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-3"
              style={{ color: COLORS.paper, fontFamily: "'Work Sans', sans-serif" }}
            >
              <span
                className="w-10 h-10 rounded-full flex items-center justify-center"
                style={{ background: "rgba(232,162,58,0.15)" }}
              >
                <Instagram size={18} color={COLORS.paper} />
              </span>
              @hifivediscos
            </a>
          </div>
        </Reveal>

        <Reveal delay={0.1}>
          <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <input
              required
              placeholder="Seu nome"
              value={form.nome}
              onChange={(e) => setForm({ ...form, nome: e.target.value })}
              className="px-4 py-3 rounded-lg outline-none"
              style={inputStyle}
            />
            <input
              placeholder="Telefone (opcional)"
              value={form.telefone}
              onChange={(e) => setForm({ ...form, telefone: e.target.value })}
              className="px-4 py-3 rounded-lg outline-none"
              style={inputStyle}
            />
            <textarea
              required
              placeholder="Sua mensagem"
              rows={4}
              value={form.mensagem}
              onChange={(e) => setForm({ ...form, mensagem: e.target.value })}
              className="px-4 py-3 rounded-lg outline-none resize-none"
              style={inputStyle}
            />
            <button
              type="submit"
              className="flex items-center justify-center gap-2 px-6 py-3 rounded-full font-medium"
              style={{ background: COLORS.paper, color: COLORS.ink, fontFamily: "'Work Sans', sans-serif" }}
            >
              Enviar pelo WhatsApp
              <Send size={16} />
            </button>
            <p className="text-xs" style={{ color: "rgba(244,235,214,0.4)", fontFamily: "'Work Sans', sans-serif" }}>
              Ao enviar, o WhatsApp abre com sua mensagem pronta pra disparar.
            </p>
          </form>
        </Reveal>
      </div>
    </section>
  );
}

